-- IT岗位招聘数据分析项目 - 数据库导出
-- 数据库: job_analysis

CREATE DATABASE IF NOT EXISTS job_analysis DEFAULT CHARSET utf8mb4;
USE job_analysis;

DROP TABLE IF EXISTS job_listing;
CREATE TABLE `job_listing` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '自增ID',
  `job_title` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '岗位名称',
  `job_url` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '51job详情链接',
  `keyword` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '搜索关键词（数据分析/Python开发/AI算法/大数据开发）',
  `salary_text` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '薪资原文（如15-25K·14薪）',
  `salary_min` decimal(10,2) DEFAULT NULL COMMENT '最低月薪(元)',
  `salary_max` decimal(10,2) DEFAULT NULL COMMENT '最高月薪(元)',
  `salary_avg` decimal(10,2) DEFAULT NULL COMMENT '平均月薪(元) = (min+max)/2',
  `city` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '城市（标准化后，如北京/上海）',
  `district` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '区/县',
  `city_tier` enum('一线','新一线','二线','其他') COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '城市等级',
  `education` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '学历要求（不限/大专/本科/硕士/博士）',
  `experience` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '经验要求原文（如3-5年）',
  `exp_min` decimal(4,1) DEFAULT '0.0' COMMENT '最低经验(年)',
  `exp_max` decimal(4,1) DEFAULT '0.0' COMMENT '最高经验(年)',
  `company_name` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '公司名称',
  `company_size` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '公司规模（如500-1000人）',
  `industry` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '所属行业',
  `skill_tags` text COLLATE utf8mb4_unicode_ci COMMENT '技能标签（逗号分隔，如Python,SQL,Spark）',
  `publish_date` date DEFAULT NULL COMMENT '发布日期',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '入库时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_url` (`job_url`(255)),
  KEY `idx_city` (`city`),
  KEY `idx_education` (`education`),
  KEY `idx_salary_avg` (`salary_avg`),
  KEY `idx_keyword` (`keyword`),
  KEY `idx_publish` (`publish_date`),
  KEY `idx_city_salary` (`city`,`salary_avg`)
) ENGINE=InnoDB AUTO_INCREMENT=410 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='IT岗位招聘数据';

-- job_listing data: 409 rows

DROP TABLE IF EXISTS job_skill;
CREATE TABLE `job_skill` (
  `id` int NOT NULL AUTO_INCREMENT,
  `job_id` int NOT NULL COMMENT '关联job_listing.id',
  `skill_name` varchar(100) NOT NULL COMMENT '技能名称（如Python、SQL）',
  PRIMARY KEY (`id`),
  KEY `idx_skill` (`skill_name`),
  KEY `idx_job_id` (`job_id`),
  CONSTRAINT `job_skill_ibfk_1` FOREIGN KEY (`job_id`) REFERENCES `job_listing` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='技能-岗位关联表';

DROP TABLE IF EXISTS analysis_result;
CREATE TABLE `analysis_result` (
  `id` int NOT NULL AUTO_INCREMENT,
  `result_name` varchar(100) NOT NULL COMMENT '分析名称（如salary_by_city）',
  `result_data` json NOT NULL COMMENT '分析结果JSON',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_name` (`result_name`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='分析结果缓存';

